sql:
SELECT SUM(quantity) 
FROM project_mixes 
WHERE project_id = (SELECT project_id FROM projects WHERE project_name = 'Project Alpha');

SELECT AVG(compressive_strength) 
FROM strength_tests
WHERE conducted_by = 1;

SELECT MAX(compressive_strength) 
FROM strength_tests
WHERE mix_id = 1;

SELECT MAX(compressive_strength) 
FROM strength_tests 
WHERE mix_id IN (SELECT mix_id FROM project_mixes WHERE project_id = 1);

SELECT AVG(compressive_strength) AS average_compressive_strength
FROM strength_tests
WHERE mix_id = 1;

SELECT SUM(cement) AS cement_used
FROM concrete_mixes
WHERE mix_name LIKE '%High-Strength%';

SELECT mix_name
FROM concrete_mixes
WHERE created_date LIKE '2023-%';

SELECT mix_name
FROM concrete_mixes
WHERE mix_id = (SELECT mix_id FROM strength_tests WHERE test_id = 0);

SELECT SUM(amount) AS total_amount
FROM mix_ingredients
WHERE mix_id = 1;

SELECT 
    (SELECT SUM(quantity) FROM project_mixes WHERE mix_id = 1) AS total_quantity,
    (SELECT AVG(compressive_strength) FROM strength_tests WHERE mix_id = 1 AND age = 28) AS average_compressive_strength;

SELECT mix_id, mix_name, created_date
FROM concrete_mixes
WHERE created_date = (
    SELECT MIN(created_date)
    FROM concrete_mixes
);
